final:
module top_module(J,K,Q,Qnot,CP);input J,K,CP;
	output Q,Qnot;
	reg Q;

	assign Qnot = ~Q;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CP or posedge dbg_halt)
		case({J,K})
			2'b00: Q = Q;
			2'b01: Q = 0;
			2'b10: Q = 1;
			2'b11: Q = ~Q;
			default: ;
		endcase
endmodule
